// 1. Define tu logo aquí (Pega tu cadena Base64)
const MI_LOGO_BASE64 = "data:image/png;base64,"; 

function generatePdf() {
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF('p', 'mm', 'a4');
    const pageWidth = doc.internal.pageSize.getWidth();
    
    // --- ENCABEZADO Y LOGO ---
    try {
        // x: 15, y: 10, width: 30, height: 15 (ajusta según tu logo)
        doc.addImage(MI_LOGO_BASE64, 'PNG', 15, 10, 30, 15);
    } catch (e) {
        console.log("No se pudo cargar el logo, asegúrate de que sea Base64 válido.");
    }

    // --- DATOS DEL CLIENTE (Basado en captura 6.50.39) ---
    const custData = [
        ['Customer Info.', document.getElementById('pdfCustomer').value],
        ['Machine Model', document.getElementById('pdfModel').value],
        ['System S/N', document.getElementById('pdfSN').value],
        ['SMTo Engineer', document.getElementById('pdfEngineer').value]
    ];

    doc.autoTable({
        body: custData,
        startY: 30,
        theme: 'grid',
        styles: { fontSize: 9, cellPadding: 1, lineColor: [0, 0, 0], lineWidth: 0.2 },
        columnStyles: { 0: { fontStyle: 'bold', fillColor: [240, 240, 240], width: 40 } }
    });

    let currentY = doc.lastAutoTable.finalY + 10;

    // --- PROCESAR LAS 3 MAGNIFICACIONES (M11, M15, M19) ---
    const mags = ['highM11', 'lowM15', 'lowM19'];

    mags.forEach((magKey) => {
        const lim = LIMITS[magKey];
        const dataForMag = allLogData.filter(d => d.magType === magKey);
        
        // Si no hay datos para esta magnificación, saltar o poner valores en 0
        const valsX = dataForMag.map(d => d.x);
        const valsY = dataForMag.map(d => d.y);
        
        const sX = valsX.length > 0 ? calcStats(valsX, lim.xLSL, lim.xUSL) : { sd:0, mean:0, cpk:0 };
        const sY = valsY.length > 0 ? calcStats(valsY, lim.yLSL, lim.yUSL) : { sd:0, mean:0, cpk:0 };

        // Título de la sección (ej: High Magnification (M11))
        doc.setFontSize(12);
        doc.setFont("helvetica", "bold");
        doc.text(lim.name, pageWidth / 2, currentY, { align: 'center' });
        currentY += 5;

        // Tabla de estadísticas (Estilo captura 6.40.37)
        doc.autoTable({
            head: [['', 'X-ray Spot (X)', 'X-ray Spot (Y)']],
            body: [
                ['Standard Deviation', sX.sd.toFixed(4), sY.sd.toFixed(4)],
                ['Mean', sX.mean.toFixed(0), sY.mean.toFixed(0)],
                ['USL', lim.xUSL.toLocaleString(), lim.yUSL.toLocaleString()],
                ['LSL', lim.xLSL.toLocaleString(), lim.yLSL.toLocaleString()],
                ['Cpk', sX.cpk.toFixed(12), sY.cpk.toFixed(12)],
                ['Principle', getP(sX.cpk).t, getP(sY.cpk).t]
            ],
            startY: currentY,
            theme: 'grid',
            headStyles: { fillColor: [255, 255, 255], textColor: [0, 0, 0], fontStyle: 'bold', halign: 'center', lineWidth: 0.2 },
            styles: { fontSize: 8, halign: 'center', lineColor: [0, 0, 0], lineWidth: 0.2 },
            columnStyles: { 0: { halign: 'left', fontStyle: 'bold', fillColor: [245, 245, 245] } },
            // Aplicar colores de "Principle" a la última fila
            didParseCell: function(data) {
                if (data.section === 'body' && data.row.index === 5 && data.column.index > 0) {
                    const val = data.cell.raw;
                    if (val === 'Excellent') data.cell.styles.fillColor = [48, 209, 88];
                    if (val === 'Optimal') data.cell.styles.fillColor = [100, 210, 255];
                    if (val === 'Good') data.cell.styles.fillColor = [200, 255, 200];
                }
            }
        });

        currentY = doc.lastAutoTable.finalY + 10;
    });

    // --- TABLA DE REFERENCIA CPK (Captura 6.56.29) ---
    doc.autoTable({
        head: [['CPK', 'Principle']],
        body: [
            ['CPK >= 2.0', 'Excellent'],
            ['2.0 > CPK >= 1.67', 'Optimal'],
            ['1.67 > CPK >= 1.33', 'Good'],
            ['1.33 > CPK >= 1.0', 'Acceptable'],
            ['1.0 > CPK >= 0.67', 'Bad'],
            ['0.67 > CPK', 'Terrible']
        ],
        startY: currentY,
        margin: { right: 120 }, // Hacerla pequeña a la izquierda
        theme: 'grid',
        styles: { fontSize: 7, cellPadding: 0.5 },
        headStyles: { fillColor: [0, 0, 0] },
        didParseCell: function(data) {
            if (data.column.index === 1) {
                if (data.row.index === 0) data.cell.styles.fillColor = [48, 209, 88];
                if (data.row.index === 1) data.cell.styles.fillColor = [100, 210, 255];
                if (data.row.index === 2) data.cell.styles.fillColor = [173, 216, 230];
                if (data.row.index === 3) data.cell.styles.fillColor = [255, 255, 0];
                if (data.row.index === 4) data.cell.styles.fillColor = [255, 165, 0];
                if (data.row.index === 5) data.cell.styles.fillColor = [255, 0, 0];
            }
        }
    });

    doc.save(`Reporte_Final_Vitrox_AXI.pdf`);
    closePdfModal();
}
